import{_ as o,o as t,c as a,au as s}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Authorisation hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/hooks/hooks.authorisations.md","filePath":"api/core/hooks/hooks.authorisations.md"}'),r={name:"api/core/hooks/hooks.authorisations.md"};function i(c,e,d,h,n,u){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="authorisation-hooks" tabindex="-1">Authorisation hooks <a class="header-anchor" href="#authorisation-hooks" aria-label="Permalink to &quot;Authorisation hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for the CASL-based authorisation system: populating subjects and resources, enforcing access control, preventing privilege escalation, updating the abilities cache, and generating JWT tokens.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="createjwt-options" tabindex="-1"><code>createJWT(options?)</code> <a class="header-anchor" href="#createjwt-options" aria-label="Permalink to &quot;`createJWT(options?)`&quot;">​</a></h3><blockquote><p>Returns a hook function.</p></blockquote><p>Generates JWT access tokens for each item in the hook result using the application&#39;s authentication service, and stores them on the item.</p><h4 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>name</code></td><td>string</td><td>Property name to store the token on each item (default: <code>&#39;accessToken&#39;</code>)</td></tr><tr><td><code>payload</code></td><td>Function</td><td><code>(user) =&gt; Object</code> — custom JWT payload properties</td></tr><tr><td><code>jwt</code></td><td>Function</td><td><code>(user) =&gt; Object</code> — custom JWT sign options merged with the application defaults</td></tr></tbody></table><hr><h3 id="populatesubjects-hook" tabindex="-1"><code>populateSubjects(hook)</code> <a class="header-anchor" href="#populatesubjects-hook" aria-label="Permalink to &quot;`populateSubjects(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook.</p></blockquote><p>Retrieves authorisation subject object(s) from their service and stores them in <code>hook.params.subjects</code>.</p><p>Specialises <a href="./hooks.query.html#populateobjectsoptions"><code>populateObjects</code></a> with:</p><ul><li><code>serviceField: &#39;subjectsService&#39;</code></li><li><code>idField: &#39;subjects&#39;</code></li><li><code>throwOnNotFound: true</code></li></ul><hr><h3 id="unpopulatesubjects-hook" tabindex="-1"><code>unpopulateSubjects(hook)</code> <a class="header-anchor" href="#unpopulatesubjects-hook" aria-label="Permalink to &quot;`unpopulateSubjects(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after</code> hook.</p></blockquote><p>Removes the <code>subjects</code> and <code>subjectsService</code> properties set by <code>populateSubjects</code> from <code>hook.params</code>.</p><hr><h3 id="populateresource-hook" tabindex="-1"><code>populateResource(hook)</code> <a class="header-anchor" href="#populateresource-hook" aria-label="Permalink to &quot;`populateResource(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook.</p></blockquote><p>Retrieves the authorisation resource object from its service and stores it in <code>hook.params.resource</code>.</p><p>Specialises <a href="./hooks.query.html#populateobjectoptions"><code>populateObject</code></a> with:</p><ul><li><code>serviceField: &#39;resourcesService&#39;</code></li><li><code>idField: &#39;resource&#39;</code></li><li><code>throwOnNotFound: true</code></li></ul><hr><h3 id="unpopulateresource-hook" tabindex="-1"><code>unpopulateResource(hook)</code> <a class="header-anchor" href="#unpopulateresource-hook" aria-label="Permalink to &quot;`unpopulateResource(hook)`&quot;">​</a></h3><blockquote><p>To be used as an <code>after</code> hook.</p></blockquote><p>Removes the <code>resource</code> and <code>resourcesService</code> properties set by <code>populateResource</code> from <code>hook.params</code>.</p><hr><h3 id="preventescalation-hook" tabindex="-1"><code>preventEscalation(hook)</code> <a class="header-anchor" href="#preventescalation-hook" aria-label="Permalink to &quot;`preventEscalation(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook.</p></blockquote><p>Prevents privilege escalation during authorisation <code>create</code> and <code>remove</code> operations. Checks that:</p><ul><li>Users cannot grant permissions higher than their own.</li><li>Users cannot modify or remove subjects whose permissions exceed their own.</li></ul><p>By default, only applied to external (provider) requests. Can be overridden with <code>hook.params.checkEscalation</code>.</p><hr><h3 id="authorise-hook" tabindex="-1"><code>authorise(hook)</code> <a class="header-anchor" href="#authorise-hook" aria-label="Permalink to &quot;`authorise(hook)`&quot;">​</a></h3><blockquote><p>Usually used as an app-level <code>before</code> hook.</p></blockquote><p>Checks whether the current user has the required CASL abilities to perform the requested operation on the target resource. Builds the ability for the user via the authorisations service, then:</p><ul><li>For <code>create</code> and custom methods: checks the data object directly.</li><li>For <code>find/update/patch/remove</code>: injects ability constraints into the query so only authorised items are returned.</li><li>For <code>get/update/patch/remove</code> with a specific ID: fetches the item first and checks permissions against it.</li></ul><p>Sets <code>hook.params.authorised = true</code> when access is granted.</p><blockquote><p>By default, only applies to external (provider) requests. Override with <code>hook.params.checkAuthorisation</code>.</p></blockquote><hr><h3 id="updateabilities-options" tabindex="-1"><code>updateAbilities(options?)</code> <a class="header-anchor" href="#updateabilities-options" aria-label="Permalink to &quot;`updateAbilities(options?)`&quot;">​</a></h3><blockquote><p>Returns a hook function.</p></blockquote><p>Updates the CASL abilities cache for a subject after their permissions have changed.</p><h4 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>subjectAsItem</code></td><td>boolean</td><td>If <code>true</code>, the subject is the hook result item (e.g. on the users service). If <code>false</code>, uses <code>hook.params.user</code>.</td></tr><tr><td><code>fetchSubject</code></td><td>boolean</td><td>If <code>true</code>, re-fetches the full subject from the users service before recomputing abilities (useful when the item is a partial patch result).</td></tr></tbody></table>',48)])])}const b=o(r,[["render",i]]);export{p as __pageData,b as default};
